FUNCTION CalculateFunctionPoints(ei, eo, eq, ilf, eif, gscSum)
 // Complexity weights: [Simple, Average, Complex]
 weights = {
 ei: [3, 4, 6],
 eo: [4, 5, 7],
 eq: [3, 4, 6],
 ilf: [7, 10, 15],
 eif: [5, 7, 10]
 }

 // Calculate unadjusted FP
 ufp = (ei.simple*weights.ei[0]) + (ei.average*weights.ei[1]) + (ei.complex*weights.ei[2])
 ufp = ufp + (eo.simple*weights.eo[0]) + (eo.average*weights.eo[1]) + (eo.complex*weights.eo[2])
 ufp = ufp + (eq.simple*weights.eq[0]) + (eq.average*weights.eq[1]) + (eq.complex*weights.eq[2])
 ufp = ufp + (ilf.simple*weights.ilf[0]) + (ilf.average*weights.ilf[1]) + (ilf.complex*weights.ilf[2])
 ufp = ufp + (eif.simple*weights.eif[0]) + (eif.average*weights.eif[1]) + (eif.complex*weights.eif[2])

 // Calculate Complexity Adjustment Factor
 caf = 0.65 + (0.01 * gscSum)

 // Calculate Adjusted Function Points
 afp = ufp * caf

 RETURN {ufp, caf, afp}
END FUNCTION

FUNCTION CalculateIntermediateCOCOMO(kloc, mode, costDrivers)
 // Step 1: Calculate base effort
 baseEffort = CalculateBasicCOCOMO(kloc, mode)

 // Step 2: Calculate Effort Multiplier from cost drivers
 effortMultiplier = 1.0
 FOR each driver IN costDrivers
 effortMultiplier = effortMultiplier * driver.multiplier
 END FOR

 // Common cost driver multipliers (rating 1=nominal):
 // RELY: [0.75, 0.88, 1.00, 1.15, 1.24, 1.40]
 // CPLX: [0.70, 0.85, 1.00, 1.15, 1.30, 1.65]
 // ACAP: [1.46, 1.19, 1.00, 0.86, 0.71]
 // ... (15 drivers total)

 // Step 3: Calculate adjusted effort
 adjustedEffort = baseEffort * effortMultiplier

 // Step 4: Calculate development time
 c = [2.5, 2.5, 2.5] // for modes 1,2,3
 d = [0.38, 0.35, 0.32]
 devTime = c[mode] * (adjustedEffort ^ d[mode])

 RETURN {effort: adjustedEffort, time: devTime}
END FUNCTION

FUNCTION CalculateUCPEffort(actors, useCases, tcfFactors, ecfFactors)
 // Step 1: Count Unadjusted Use Case Points
 actorWeight = {
 Simple: 1, // Other application or DB
 Average: 2, // Interactive, API
 Complex: 3 // GUI-based interaction
 }
 ucWeight = {
 Simple: 5, // <4 transactions
 Average: 10, // 4-7 transactions
 Complex: 15 // >7 transactions
 }

 uucp = 0
 FOR each actor IN actors
 uucp = uucp + actorWeight[actor.type]
 END FOR

 FOR each uc IN useCases
 uucp = uucp + ucWeight[uc.type]
 END FOR

 // Step 2: Calculate Technical Complexity Factor
 tcf = 0.8 + (0.01 * sum(tcfFactors)) // 13 factors, 0-5 each

 // Step 3: Calculate Environmental Complexity Factor
 ecf = 1.4 + (-0.03 * sum(ecfFactors)) // 8 factors, 0-5 each

 // Step 4: Calculate Use Case Points
 ucp = uucp * tcf * ecf

 // Step 5: Estimate effort (typically 16-30 hours per UCP)
 avgHoursPerUCP = 20 // Can be calibrated
 totalEffortHours = ucp * avgHoursPerUCP

 RETURN {uucp: uucp, tcf: tcf, ecf: ecf, ucp: ucp, hours: totalEffortHours}
END FUNCTION
